+fn arb_pane_direction() -> impl Strategy<Value = PaneDirection> {
+    prop_oneof![
+        Just(PaneDirection::Up),
+        Just(PaneDirection::Down),
+        Just(PaneDirection::Left),
+        Just(PaneDirection::Right),
+        Just(PaneDirection::Next),
+        Just(PaneDirection::Prev),
+    ]
+}
